SELECT
    r.id, r.patrol_id, c.patrol_name, r.success, r.response_code, r.response_time,
    r.response_body, r.error_message, r.ai_report, r.create_time
FROM api_patrol_result r
LEFT JOIN api_patrol_config c ON r.patrol_id = c.id


        AND r.id = #{id}


        AND r.patrol_id = #{patrolId}


        AND r.success = #{success}


        AND c.patrol_name LIKE CONCAT('%', #{patrolName}, '%')


ORDER BY r.create_time DESC

    LIMIT #{offset}, #{limit}

